import { Component, h, Prop, Element, State, AttachInternals, Method, Watch, Event, EventEmitter, Listen } from '@stencil/core';
import { customTwMerge, findAssignedElementsByTag } from '../../utils/utils';
import { cardBaseBorderClasses, cardBaseClasses, cardDisabledClasses, cardElevationClasses, cardGhostBorderClasses, cardNoElevationClasses } from '../../utils/card-content-renderer';
import { getCardStateClasses, handleCardKeyDown, handleCardClick } from '../../utils/card.util';

type CardVariant = 'actionable' | 'selectable' | 'non-actionable';

@Component({
  tag: 'wdpr-card-medium',
  shadow: true,
  styles: `:host { display: block; width: 100%; }`,
  formAssociated: true,
})
export class WdprCardMedium {
  @Element() el: HTMLElement;

  @Prop({ reflect: true }) variant: CardVariant = 'actionable';
  @Prop() mediaPosition: 'leading' | 'trailing' | 'none' = 'leading';
  @Prop({ reflect: true, mutable: true }) ghost: boolean = false;
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ reflect: true }) name?: string;

  @Prop({ reflect: true }) fullWidth: boolean = false;
  @Prop() mediaAspect: 'portrait' | '3:2' = 'portrait';
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;

  @State() _selected: boolean = false;
  @State() _isMouseDown: boolean = false;

  @Event() wdprCardClick: EventEmitter<{ selected: boolean }>;
  @Event({ eventName: 'wdprDisabledChange' }) wdprDisabledChange!: EventEmitter<boolean>;

  private _wdprCardMediumContent: HTMLWdprCardMediumContentElement[] | undefined;

  @AttachInternals()
  internals: ElementInternals;

  componentDidLoad() {
    this._findCardContent();
    this._updateFormValue();
  }

  @Method()
  async refreshInternals() {
    this._updateFormValue();
  }

  @Watch('disabled')
  handleDisabledChange() {
    this._findCardContent();
    this.wdprDisabledChange?.emit(this.disabled);
    this._updateFormValue();
  }

  @Watch('_selected')
  onSelectedPropChange() {
    this._updateFormValue();
  }

  @Listen('formreset')
  handleFormReset() {
    this._selected = false;
    this._updateFormValue();
  }

  private _handleSelectedChange = () => {
    if (this.variant === 'non-actionable') return;

    this._selected = this.variant === 'selectable' ? !this._selected : false;

    this.wdprCardClick.emit({ selected: this._selected });
  };

  private _updateFormValue = () => {
    const shouldSubmit = !this.disabled;
    const formValue = shouldSubmit ? (this._selected ? 'selected' : 'not selected') : null;

    queueMicrotask(() => {
      if (this.internals && this.name != null) {
        this.internals?.setFormValue?.(formValue);
      }
    });
    this._updateValidity();
  };

  private _updateValidity = () => {
    if (this.disabled) {
      this.internals?.setValidity?.({});

      return;
    }

    const isValid = this._selected != null && typeof this._selected === 'boolean';
    if (isValid) {
      this.internals?.setValidity?.({});
    } else {
      this.internals?.setValidity?.({ valueMissing: true }, 'this field is required');
    }
  };

  private _findCardContent = () => {
    const slot = this.el.shadowRoot?.querySelector('slot[name="content"]');

    if (slot) {
      const assignedElement = findAssignedElementsByTag(slot as HTMLSlotElement, 'wdpr-card-medium-content');
      this._wdprCardMediumContent = assignedElement as HTMLWdprCardMediumContentElement[] | undefined;

      if (this._wdprCardMediumContent) {
        this._wdprCardMediumContent.forEach(content => {
          const button = content.querySelector?.('wdpr-button');
          if (button) {
            button.disabled = this.disabled;
          }

          content.disabled = this.disabled;
        });
      }
    }
  };

  private _handleKeyDown = (e: KeyboardEvent) => {
    handleCardKeyDown(e, this.el, this.disabled, this._handleSelectedChange);
  };

  private _handleClick = (e: MouseEvent) => {
    handleCardClick(e, this.disabled, this._handleSelectedChange);
  };

  get mediaSlotDimensions() {
    return this.mediaAspect === '3:2' ? 'w-48' : 'w-24 h-32';
  }

  get mediaSlot() {
    if (this.mediaPosition === 'none') {
      return null;
    }
    const margin = this.mediaPosition === 'leading' ? 'mr-200' : 'ml-200';

    return (
      <div class={`relative block items-center shrink-0 ${this.mediaSlotDimensions} rounded-150 h-full overflow-hidden ${margin}`}>
        {this.disabled && (
          <div class="z-10 w-full h-full absolute">
            <wdpr-overlay cover open variant="scrim" role="presentation" ariaLabel="Disabled Overlay" />
          </div>
        )}
        <slot name="media" />
        <div class={`absolute top-1 ${this.mediaPosition === 'leading' ? 'left-1' : 'right-1'}`}>
          <slot name="favorite-button" />
        </div>
      </div>
    );
  }

  get cardPaddingClasses(): string {
    if (this.mediaPosition === 'none') {
      return 'py-100 px-200';
    }
    if (this.mediaPosition === 'leading') {
      return 'py-100 pr-200 pl-100';
    }
    if (this.mediaPosition === 'trailing') {
      return 'py-100 pl-200 pr-100';
    }

    return '';
  }

  get cardCardCursorClasses() {
    if (this.disabled || this.variant === 'non-actionable') return 'cursor-default';

    return 'cursor-pointer';
  }

  get cardClasses() {
    const cardWidthClasses = this.fullWidth ? '!w-full sm:!w-full !min-w-0 !max-w-none' : '';

    if (this.disabled) {
      const elevationClasses = (this.variant === 'non-actionable') ? 'elevation-none' : 'elevation-small-soft';

      return customTwMerge(cardDisabledClasses, cardWidthClasses, elevationClasses);
    }

    const cardStateClasses = !this.ghost && this.variant !== 'non-actionable' ? getCardStateClasses(this._selected, this._isMouseDown) : '';
    const cardBorderClasses = this.ghost ? cardGhostBorderClasses : this.variant !== 'non-actionable' ? cardBaseBorderClasses : '';
    const cardShadowBoxClasses = this.ghost || this.variant === 'non-actionable' ? cardNoElevationClasses : cardElevationClasses;
    const cardCursorClasses = this.cardCardCursorClasses;

    return customTwMerge(
      cardBaseClasses,
      cardBorderClasses,
      cardShadowBoxClasses,
      cardWidthClasses,
      cardCursorClasses,
      cardStateClasses
    );
  }

  render() {
    return (
      <div
        class={this.cardClasses}
        tabIndex={this.disabled ? -1 : 0}
        onClick={this._handleClick}
        onKeyDown={this._handleKeyDown}
        onMouseDown={() => this._isMouseDown = true}
        onMouseUp={() => this._isMouseDown = false}
      >
        <div class={`flex flex-1 w-full pb-100 ${this.cardPaddingClasses}`}>
          {this.mediaPosition === 'leading' && this.mediaSlot}

          <div part='content' class="flex-col flex flex-1 min-w-0">
            <div class="flex items-start">
              <slot name="badge" />
            </div>
            <div class="flex-col flex mt-100">
              <slot name="content" />
            </div>
          </div>

          {this.mediaPosition === 'trailing' && this.mediaSlot}
        </div>

        <div class="flex flex-col w-full">
          <slot name="footer" />
        </div>
      </div>

    );
  }
}